b7311ffe-7096-4c6b-80a9-5cdd5b94533c	9bb2e6c4-2d0d-4b83-804e-1af8d4aeb324	catalog.product.update	product	0fc13ddf-9d89-41a1-a70e-be32abcba88d	{"id": "0fc13ddf-9d89-41a1-a70e-be32abcba88d", "name": "Bolt.new Pro 12 Months Subscription", "slug": "bolt-new-pro-12-months", "status": "active", "category": "AI", "logo_key": "bolt-logo", "metadata": {"region": "GLOBAL", "features": ["Access to all Bolt.new Pro features."], "platform": "Bolt.new", "info_box_text": "This product is applied to your personal Bolt.new account.\\nIf you do not currently have a Bolt.new account, SubSlush can apply it to a newly provisioned account when you select Upgrade New Account.\\nDelivery is completed by applying a 100% off activation code to your account.\\nAfter activation, do not change the billing method or upgrade the plan in the Bolt.new dashboard, as this may trigger automatic cancellation by Bolt.new's internal system.\\nSubSlush is not responsible for cancellations caused by user-side account changes.", "upgrade_options": {"allow_new_account": true, "allow_own_account": true, "manual_monthly_upgrade": false, "own_account_credential_requirement": "email_and_password"}, "activation_guide": "Place your order and choose your upgrade option: Upgrade Own Account or Upgrade New Account (use Upgrade New Account if you do not have a Bolt.new account).\\nIf you choose Upgrade Own Account, share your Bolt.new account email and password with SubSlush for fulfillment.\\nIf you choose Upgrade New Account, no account details are needed; SubSlush will provision a new Bolt.new account for you.\\nYour order is then handled by the SubSlush manual fulfillment queue. The team delivers the product by applying a 100% off activation code to the account.\\nMost orders are completed within 24 hours, but delivery can take up to 72 hours.\\nOnce activation is completed, you will receive an email notification; if you selected Upgrade New Account, that email will include your login credentials (email and password).\\nAfter activation, do not change the billing method or upgrade the plan in the Bolt.new dashboard, as this can trigger automatic cancellation by Bolt.new's internal system.", "comparison_price_cents": 21600}, "created_at": "2026-03-24T23:20:57.054Z", "updated_at": "2026-03-24T23:20:57.054Z", "description": "Access Bolt.new Pro on your personal account with manual fulfillment by SubSlush.", "service_type": "bolt_new", "sub_category": "Bolt.new", "duration_months": 12, "default_currency": "USD", "fixed_price_cents": 9999, "max_subscriptions": null, "fixed_price_currency": "USD"}	{"id": "0fc13ddf-9d89-41a1-a70e-be32abcba88d", "name": "Bolt.new Pro 12 Months Subscription", "slug": "bolt-new-pro-12-months", "status": "active", "category": "AI", "logo_key": "bolt-logo", "metadata": {"region": "GLOBAL", "features": ["Access to all Bolt.new Pro features."], "platform": "Bolt.new", "info_box_text": "This product is applied to your personal Bolt.new account.\\nIf you do not currently have a Bolt.new account, SubSlush can apply it to a newly provisioned account when you select Upgrade New Account.\\n\\nDelivery is completed by applying a 100% off activation code to your account.\\nAfter activation, do not change the billing method or upgrade the plan in the Bolt.new dashboard, as this may trigger automatic cancellation by Bolt.new's internal system.\\nSubSlush is not responsible for cancellations caused by user-side account changes.", "upgrade_options": {"allow_new_account": true, "allow_own_account": true, "manual_monthly_upgrade": false, "own_account_credential_requirement": "email_and_password"}, "activation_guide": "Place your order and choose your upgrade option: Upgrade Own Account or Upgrade New Account (use Upgrade New Account if you do not have a Bolt.new account).\\nIf you choose Upgrade Own Account, share your Bolt.new account email and password with SubSlush for fulfillment.\\nIf you choose Upgrade New Account, no account details are needed; SubSlush will provision a new Bolt.new account for you.\\nYour order is then handled by the SubSlush manual fulfillment queue. The team delivers the product by applying a 100% off activation code to the account.\\nMost orders are completed within 24 hours, but delivery can take up to 72 hours.\\nOnce activation is completed, you will receive an email notification; if you selected Upgrade New Account, that email will include your login credentials (email and password).\\nAfter activation, do not change the billing method or upgrade the plan in the Bolt.new dashboard, as this can trigger automatic cancellation by Bolt.new's internal system.", "comparison_price_cents": 21600}, "created_at": "2026-03-24T23:20:57.054Z", "updated_at": "2026-03-24T23:29:05.071Z", "description": "Access Bolt.new Pro on your personal account with manual fulfillment by SubSlush.", "service_type": "bolt_new", "sub_category": "Bolt.new", "duration_months": 12, "default_currency": "USD", "fixed_price_cents": 9999, "max_subscriptions": null, "fixed_price_currency": "USD"}	{"updatedFields": ["name", "slug", "description", "service_type", "logo_key", "category", "sub_category", "duration_months", "fixed_price_cents", "fixed_price_currency", "status", "metadata"]}	127.0.0.1	Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36	req-ak	2026-03-25 00:29:05.077415
